print('scipy', scipy.__version__)
def feasible_pattern(n,k,good_set,eps=1e-9):
    # constraints: x>=0, sum x=1; for j in good sum window >=k/n; for bad <=k/n maybe strict, use <=
    A_ub=[]; b_ub=[]
    for j in range(n):
        coeff=np.zeros(n)
        for t in range(k):
            coeff[(j+t)%n]=1
        if j in good_set:
            A_ub.append(-coeff); b_ub.append(-k/n)
        else:
            A_ub.append(coeff); b_ub.append(k/n - eps)
    res=opt.linprog(c=np.zeros(n), A_ub=np.array(A_ub), b_ub=np.array(b_ub),
                    A_eq=np.ones((1,n)), b_eq=[1], bounds=[(0,None)]*n, method='highs')
    return res.success, res.x if res.success else None

def min_good_cyclic(n,k):
    for g in range(k): # less than k
        for good in itertools.combinations(range(n),g):
            ok,x=feasible_pattern(n,k,set(good),eps=1e-7)
            if ok:
                return g,good,x
    return None
