from functools import lru_cache
def dist_coeffs(c,p):
    # dict sum prob for centered X=sum c(zeta-p)
    q=1-p
    d={0.0:1.0}
    for a in c:
        nd={}
        for x,pr in d.items():
            nd[x+q*a]=nd.get(x+q*a,0)+pr*p
            nd[x-p*a]=nd.get(x-p*a,0)+pr*q
        d=nd
    return d
def F_val(c,p,x=0):
    q=1-p
    d=dist_coeffs(c,p)
    return q*sum(pr for s,pr in d.items() if s >= p+x-1e-12) - p*sum(pr for s,pr in d.items() if s < -q+x-1e-12)
